static SDDL2_Type primitive_type(SDDL2_Type_kind kind, uint32_t width)
{
    SDDL2_Type type{};
    type.kind         = kind;
    type.width        = width;
    type.complex_data = nullptr;
    return type;
}

static SDDL2_ReplaySegment primitive_replay_segment(
        size_t size_bytes,
        SDDL2_Type_kind kind,
        uint32_t width)
{
    SDDL2_ReplaySegment segment{};
    segment.size_bytes = size_bytes;
    segment.type       = primitive_type(kind, width);
    return segment;
}

static SDDL2_Struct_data* create_structure_data(
        const SDDL2_Type* members,
        size_t member_count)
{
    size_t const alloc_size =
            sizeof(SDDL2_Struct_data) + member_count * sizeof(*members);
    auto* const struct_data = (SDDL2_Struct_data*)malloc(alloc_size);
    assert(struct_data != nullptr);

    struct_data->member_count     = member_count;
    struct_data->total_size_bytes = 0;
    for (size_t i = 0; i < member_count; ++i) {
        struct_data->members[i] = members[i];
        struct_data->total_size_bytes +=
                openzl::sddl2::testing::getTypeSize(members[i]);
    }

    return struct_data;
}

static SDDL2_ReplaySegment structure_replay_segment(
        size_t size_bytes,
        SDDL2_Struct_data* struct_data)
{
    SDDL2_ReplaySegment segment{};
    segment.size_bytes       = size_bytes;
    segment.type.kind        = SDDL2_TYPE_STRUCTURE;
    segment.type.width       = 1;
    segment.type.struct_data = struct_data;
    return segment;
}

static void replay_roundtrip_test(
        const void* input,
        size_t inputSize,
        const SDDL2_ReplaySegment* segments,
        size_t num_segments,
        int start_stream_id,
        const char* testName)
{
    size_t const compressedBound = ZL_compressBound(inputSize);
    void* const compressed       = malloc(compressedBound);
    assert(compressed);

    size_t const compressedSize = compress_sddl2_replay_chunk(
            compressed,
            compressedBound,
            input,
            inputSize,
            segments,
            num_segments,
            start_stream_id);
    EXPECT_GT(compressedSize, 0u) << testName << ": compression returned 0";

    void* const decompressed = malloc(inputSize);
    assert(decompressed);

    size_t const decompressedSize =
            decompress(decompressed, inputSize, compressed, compressedSize);
    EXPECT_EQ(decompressedSize, inputSize)
            << testName << ": decompressed size mismatch";

    EXPECT_EQ(std::memcmp(decompressed, input, inputSize), 0)
            << testName << ": decompressed data doesn't match input";

    free(decompressed);
    free(compressed);
}

/**
 * Test: Single U8 typed segment
 *
 * Assembly source (test_data/single_u8_segment.asm):
 *   push.tag 0
 *   push.type.u8
 *   push.i32 4
 *   segment.create_tagged
 *   halt
 */
TEST(SDDL2BytecodeTest, SingleU8Segment)
{
    std::array<uint8_t, 4> input = { 0xAA, 0xBB, 0xCC, 0xDD };

    roundtrip_test(
            input.data(),
            input.size(),
            sddl2_parse_test_data::SINGLE_U8_SEGMENT.data(),
            sddl2_parse_test_data::SINGLE_U8_SEGMENT.size(),
            "SingleU8Segment");
}

