/**
 * Test: Structure array segment
 *
 * Tests the type.structure opcode in end-to-end compression/decompression.
 * This validates that structure types correctly integrate with the public
 * SDDL2 graph and that structure splitting, field type conversion, and
 * independent compression work correctly in a full round-trip scenario.
 *
 * Creates a segment containing 10 structures, where each structure is:
 *   {U8, I16LE, I32LE}
 * Total size: 10 × (1 + 2 + 4) bytes = 70 bytes
 *
 * Assembly source (test_data/struct_array_segment.asm):
 *   push.tag 200
 *   push.type.u8          ; Field 0: U8
 *   push.type.i16le       ; Field 1: I16LE
 *   push.type.i32le       ; Field 2: I32LE
 *   push.i32 3            ; 3 members
 *   type.structure        ; Creates Type{STRUCTURE{U8, I16LE, I32LE}, width=7}
 *   push.i32 10           ; Element count: 10 structures
 *   segment.create_tagged ; Creates 70-byte segment
 *   halt
 *
 * This tests the full structure split pipeline:
 *   1. The public SDDL2 graph recognizes the STRUCTURE type segment
 *   2. sddl2_apply_structure_split() decomposes into 3 field arrays:
 *      - Field 0: [10 × U8]   → Convert to U8   → COMPRESS_GENERIC
 *      - Field 1: [10 × I16LE] → Convert to I16LE → COMPRESS_GENERIC
 *      - Field 2: [10 × I32LE] → Convert to I32LE → COMPRESS_GENERIC
 *   3. Each field is independently compressed
 *   4. Decompression reconstructs the original structure layout
 */
TEST(SDDL2BytecodeTest, StructureArraySegment)
{
    // Generate 10 structures of {U8, I16LE, I32LE}
    const size_t NUM_STRUCTS = 10;

    // Pack structures as byte array (no padding)
    // Structure layout: [U8:1][I16LE:2][I32LE:4] = 7 bytes per struct
    std::vector<uint8_t> input(NUM_STRUCTS * 7);

    for (size_t i = 0; i < NUM_STRUCTS; i++) {
        size_t offset = i * 7;

        // Field 0: U8 (1 byte)
        uint8_t field0    = static_cast<uint8_t>(i * 10 + 1);
        input[offset + 0] = field0;

        // Field 1: I16LE (2 bytes, little-endian)
        int16_t field1    = static_cast<int16_t>(i * 100 + 42);
        input[offset + 1] = static_cast<uint8_t>(field1 & 0xFF);
        input[offset + 2] = static_cast<uint8_t>((field1 >> 8) & 0xFF);

        // Field 2: I32LE (4 bytes, little-endian)
        int32_t field2    = static_cast<int32_t>(i * 1000 + 12345);
        input[offset + 3] = static_cast<uint8_t>(field2 & 0xFF);
        input[offset + 4] = static_cast<uint8_t>((field2 >> 8) & 0xFF);
        input[offset + 5] = static_cast<uint8_t>((field2 >> 16) & 0xFF);
        input[offset + 6] = static_cast<uint8_t>((field2 >> 24) & 0xFF);
    }

    roundtrip_test(
            input.data(),
            input.size(),
            sddl2_parse_test_data::STRUCT_ARRAY_SEGMENT.data(),
            sddl2_parse_test_data::STRUCT_ARRAY_SEGMENT.size(),
            "StructureArraySegment");
}

TEST(SDDL2ReplayChunkTest, RoundTrip)
{
    std::array<uint8_t, 7> input = { 0x41, 0x42, 0x43, 0x34, 0x12, 0x78, 0x56 };
    std::array<SDDL2_ReplaySegment, 2> segments = {
        primitive_replay_segment(3, SDDL2_TYPE_BYTES, 3),
        primitive_replay_segment(4, SDDL2_TYPE_U16LE, 2),
    };

    replay_roundtrip_test(
            input.data(),
            input.size(),
            segments.data(),
            segments.size(),
            7,
            "ReplayChunkRoundTrip");
}

TEST(SDDL2ReplayChunkTest, RoundTripSlicedStructureChunk)
{
    std::array<SDDL2_Type, 3> const members = {
        primitive_type(SDDL2_TYPE_U8, 1),
        primitive_type(SDDL2_TYPE_I16LE, 1),
        primitive_type(SDDL2_TYPE_I32LE, 1),
    };
    SDDL2_Struct_data* const struct_data =
            create_structure_data(members.data(), members.size());

    // Mirror one middle chunk emitted from a larger structure segment: replay
    // only needs the chunk-local byte slice, its type metadata, and the
    // caller-supplied starting stream id.
    std::array<uint8_t, 28> const full_input = {
        0x11, 0x21, 0x22, 0x31, 0x32, 0x33, 0x34, 0x41, 0x51, 0x52,
        0x61, 0x62, 0x63, 0x64, 0x71, 0x81, 0x82, 0x91, 0x92, 0x93,
        0x94, 0xA1, 0xB1, 0xB2, 0xC1, 0xC2, 0xC3, 0xC4,
    };
    std::array<uint8_t, 14> input{};
    std::memcpy(input.data(), full_input.data() + 7, input.size());

    std::array<SDDL2_ReplaySegment, 1> const segments = {
        structure_replay_segment(input.size(), struct_data),
    };

    replay_roundtrip_test(
            input.data(),
            input.size(),
            segments.data(),
            segments.size(),
            3,
            "ReplayChunkSlicedStructureRoundTrip");

    free(struct_data);
}

TEST(SDDL2ReplayChunkTest, MissingSegmentsParamFails)
{
    std::array<uint8_t, 3> input = { 0x41, 0x42, 0x43 };
    std::vector<uint8_t> compressed(ZL_compressBound(input.size()));
    ZL_LocalParams const params = {};

    ReplayChunkCompressResult const result =
            compress_sddl2_replay_chunk_with_result(
                    compressed.data(),
                    compressed.size(),
                    input.data(),
                    input.size(),
                    &params);

    EXPECT_NE(ZL_isError(result.report), 0);
    EXPECT_NE(
            result.errorContext.find("requires a segments parameter"),
            std::string::npos);
}

TEST(SDDL2ReplayChunkTest, NegativeStartStreamIdFails)
{
    std::array<uint8_t, 3> input                = { 0x41, 0x42, 0x43 };
    std::array<SDDL2_ReplaySegment, 1> segments = { primitive_replay_segment(
            input.size(),
            SDDL2_TYPE_BYTES,
            static_cast<uint32_t>(input.size())) };
    std::vector<uint8_t> compressed(ZL_compressBound(input.size()));

    ZL_IntParam startStreamParam = {
        SDDL2_REPLAY_START_STREAM_ID_PARAM,
        -1,
    };
    ZL_RefParam replaySegmentsParam = {
        SDDL2_REPLAY_SEGMENTS_PARAM,
        segments.data(),
        segments.size() * sizeof(segments[0]),
    };
    ZL_LocalParams const params = {
        .intParams = { &startStreamParam, 1 },
        .refParams = { &replaySegmentsParam, 1 },
    };

    ReplayChunkCompressResult const result =
            compress_sddl2_replay_chunk_with_result(
                    compressed.data(),
                    compressed.size(),
                    input.data(),
                    input.size(),
                    &params);

    EXPECT_NE(ZL_isError(result.report), 0);
    EXPECT_NE(
            result.errorContext.find("must be non-negative"),
            std::string::npos);
}

TEST(SDDL2ReplayChunkTest, ZeroSegmentsPassthrough)
{
    std::array<uint8_t, 5> input = { 0x41, 0x42, 0x43, 0x44, 0x45 };

    replay_roundtrip_test(
            input.data(),
            input.size(),
            nullptr,
            0,
            0,
            "ReplayChunkZeroSegmentsPassthrough");
}

